import json, sys, base64, re

raw = json.load(sys.stdin)
if isinstance(raw, str): raw = json.loads(raw)
if isinstance(raw, dict) and "merged" in raw: raw = raw["merged"]

def walk(n):
    if isinstance(n, dict):
        yield n
        for v in n.values(): yield from walk(v)
    elif isinstance(n, list):
        for v in n: yield from walk(v)

tool = registry = ""
for u in walk(raw):
    if not tool and u.get("package_name"): tool = (u.get("package_name") or "").strip().lower()
    if not registry and u.get("package_registry"): registry = (u.get("package_registry") or "").strip().lower()

# Collect all manifest files (GitHub API returns base64-encoded content)
manifests = {}
for u in walk(raw):
    if isinstance(u, dict) and u.get("name") and u.get("content") and u.get("encoding") == "base64":
        try:
            manifests[u["name"].lower()] = base64.b64decode(u["content"]).decode("utf-8", "replace")
        except Exception:
            pass

def norm(n):
    # Strip version specifiers; normalize - and _ (PEP 503)
    pkg = re.split(r"[<>=!~ ;\[\(]", n.strip(), 1)[0].strip().lower()
    return pkg.replace("-", "_")

py_deps, node_deps = {}, {}
requires_python = node_engine = None

# --- requirements.txt ---
if "requirements.txt" in manifests:
    for line in manifests["requirements.txt"].splitlines():
        line = line.strip()
        if not line or line[0] in "#-": continue
        nm = norm(line)
        if nm: py_deps[nm] = line

# --- pyproject.toml (tomllib first, full regex fallback) ---
if "pyproject.toml" in manifests:
    txt = manifests["pyproject.toml"]
    parsed_ok = False
    try:
        import tomllib
        data = tomllib.loads(txt)
        proj = data.get("project", {})
        requires_python = proj.get("requires-python")
        for d in proj.get("dependencies", []) or []: py_deps[norm(d)] = d
        poetry = (data.get("tool", {}) or {}).get("poetry", {})
        for k, v in (poetry.get("dependencies", {}) or {}).items():
            if k.lower() == "python": requires_python = requires_python or str(v)
            else: py_deps[k.replace("-","_").lower()] = str(v)
        parsed_ok = True
    except Exception:
        pass

    if not parsed_ok:
        # requires-python
        m = re.search(r'requires-python\s*=\s*["\']([^"\']+)', txt)
        if m: requires_python = m.group(1)
        # PEP 621 [project.dependencies] list
        deps_block = re.search(
            r'\[project\.dependencies\]\s*\n(.*?)(?=\n\s*\[|\Z)', txt, re.DOTALL | re.IGNORECASE)
        if deps_block:
            for line in deps_block.group(1).splitlines():
                line = line.strip().strip('"').strip("'").rstrip(',')
                if line and not line.startswith('#'):
                    nm = norm(line)
                    if nm: py_deps[nm] = line
        # [tool.poetry.dependencies]
        poetry_block = re.search(
            r'\[tool\.poetry\.dependencies\]\s*\n(.*?)(?=\n\s*\[|\Z)', txt, re.DOTALL | re.IGNORECASE)
        if poetry_block:
            for line in poetry_block.group(1).splitlines():
                line = line.strip()
                if '=' in line and not line.startswith('#'):
                    k, v = line.split('=', 1)
                    k = k.strip().strip('"').replace("-","_").lower()
                    v = v.strip().strip('"').strip("'")
                    if k and k != 'python': py_deps[k] = v
                    elif k == 'python': requires_python = requires_python or v

# --- Pipfile [packages] ---
if "pipfile" in manifests:
    in_pkg = False
    for line in manifests["pipfile"].splitlines():
        stripped = line.strip()
        if stripped.lower() == '[packages]': in_pkg = True; continue
        elif stripped.startswith('[') and in_pkg: in_pkg = False
        elif in_pkg and '=' in stripped and not stripped.startswith('#'):
            k = stripped.split('=', 1)[0].strip().strip('"').replace("-","_").lower()
            if k: py_deps[k] = stripped

# --- setup.cfg install_requires ---
if "setup.cfg" in manifests:
    in_req = False
    for line in manifests["setup.cfg"].splitlines():
        s = line.strip()
        if re.match(r'install_requires\s*=', s):
            in_req = True
            after = s.split('=', 1)[1].strip()
            if after:
                nm = norm(after)
                if nm: py_deps[nm] = after
            continue
        if in_req:
            if s and not s.startswith('#') and not re.match(r'\[.*\]', s) and (line[0] in (' ','\t') or not re.match(r'\w+\s*=', s)):
                nm = norm(s)
                if nm: py_deps[nm] = s
            else:
                in_req = False

# --- package.json ---
if "package.json" in manifests:
    try:
        pj = json.loads(manifests["package.json"])
        for k, v in {**pj.get("dependencies", {}), **pj.get("devDependencies", {})}.items():
            node_deps[k.lower()] = v
        node_engine = (pj.get("engines") or {}).get("node")
    except Exception:
        pass

repo_is_python = bool(py_deps) or any(k in manifests for k in ("requirements.txt","pyproject.toml","pipfile","setup.cfg"))
repo_is_node   = bool(node_deps) or "package.json" in manifests

# Normalize tool name (- == _) for matching
tool_norm = tool.replace("-","_")

if registry in ("pypi","pip","python"):
    eco_ok, target = repo_is_python, py_deps
elif registry == "npm":
    eco_ok, target = repo_is_node, node_deps
else:
    eco_ok, target = None, {}

already = tool_norm in target if target else False
already_version = target.get(tool_norm) if already else None
dep_count = len(target)
notes, score = [], None

if not (repo_is_python or repo_is_node):
    for u in walk(raw):
        lang = (u.get("language") or "").lower()
        if lang == "python": repo_is_python = True
        elif lang in ("javascript","typescript"): repo_is_node = True
        if repo_is_python or repo_is_node:
            notes.append(f"No manifest found; ecosystem inferred from repo language ({lang}).")
            break
    if not (repo_is_python or repo_is_node):
        notes.append("No dependency manifest or language signal found in the target repo.")
elif eco_ok is None:
    notes.append("Tool registry unknown; cannot assess stack fit.")
elif not eco_ok:
    score = 15
    notes.append(f"Ecosystem mismatch: '{tool}' is a {registry} package but the repo is not {registry}-based.")
else:
    score = 70
    notes.append(f"Ecosystem match: {registry} package against a {registry}-based repo.")
    if already:
        score = 92
        notes.append(f"Already a declared dependency ({already_version}) — proven to integrate.")
    if dep_count > 40:
        score -= 8
        notes.append(f"Large dependency surface ({dep_count} deps) raises version-conflict risk.")
    elif dep_count:
        notes.append(f"{dep_count} declared dependencies.")
    if requires_python and registry in ("pypi","pip","python"):
        notes.append(f"Repo targets Python {requires_python}.")
    if node_engine and registry == "npm":
        notes.append(f"Repo targets Node {node_engine}.")

if score is not None: score = max(0, min(100, score))

manifests_found = [k for k in ("requirements.txt","pyproject.toml","pipfile","setup.cfg","package.json") if k in manifests]

print(json.dumps({
    "stack_compatibility": score,
    "data_available": score is not None,
    "evaluated_tool": tool,
    "registry": registry,
    "repo_stack": "python+node" if repo_is_python and repo_is_node else ("python" if repo_is_python else ("node" if repo_is_node else "unknown")),
    "already_dependency": already,
    "already_version": already_version,
    "declared_dependency_count": dep_count,
    "requires_python": requires_python,
    "manifests_found": manifests_found,
    "notes": notes,
}, default=str))
